px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;text-align:center;width:134.65pt;\\\">&nbsp;</td></tr><tr><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;vertical-align:top;width:184.3pt;\\\"><span style=\\\"color:hsl(0,0%,30%);\\\">JIZZAX TRK</span></td><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;text-align:center;vertical-align:top;width:7.0cm;\\\">&nbsp;</td><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;text-align:center;width:134.65pt;\\\"><span style=\\\"color:hsl(0,0%,30%);\\\">JIZZAXFM yoki JIZZAHFM</span></td></tr><tr><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;vertical-align:top;width:184.3pt;\\\"><span style=\\\"color:hsl(0,0%,30%);\\\">Live TV</span></td><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;text-align:center;vertical-align:top;width:7.0cm;\\\">&nbsp;</td><td style=\\\"border:1px dotted hsl(0, 0%, 60%);padding:0cm 5.4pt;text-align:center;width:134.65pt;\\\"><span style=\\\"color:hsl(0,0%,30%);\\\">Live</span></td></tr></tbody></table></figure>\"}', '{\"ru\": null}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"uz\": null}', '{\"ru\": null}', '{\"ru\": \"sms-golosovanie-i-pozelaniya-na-tv\", \"uz\": \"sms-ovozlar-va-tv-dagi-tilaklar\"}', 'images/x37KdmTPUl7wj3U0gze0SO3gVLoVNCrQUGO4N9wM.svg', 'images/q7HVtT3kbjVBs0PqxVskradV4YpQ8uFaFMjqWk8q.svg', 0, '2022-04-25 19:00:00', NULL, 0),
(60, 2, NULL, '{\"ru\": \"SMS-пакеты\", \"uz\": \"SMS-paketlar\"}', '{\"ru\": \"на 30 Дней\", \"uz\": \"30 kunga\"}', '{\"ru\": null}', '{\"ru\": \"<p><span style=\\\"color:rgb(255,102,0);\\\">* </span>На данную услугу действует спец. цена по программе&nbsp;<a href=\\\"http://www.perfectum.uz/service-show/programma-loyalnost\\\"><span style=\\\"color:rgb(230,0,0);\\\">\\\"Лояльность\\\"</span></a>, в зависимости от абонентского стажа (Пример: 10 лет = 10%). Чем выше стаж, тем дешевле услуги!</p><figure class=\\\"table\\\"><table><tbody><tr><td rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">№</p></td><td rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">SMS-пакет</p></td><td rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Цена</p></td><td colspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Активация</p></td><td rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Тарификация USSD/SMS</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">USSD</p></td><td><p style=\\\"text-align:center;\\\">SMS на 0777</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">1</p></td><td><p style=\\\"text-align:center;\\\">50 SMS</p></td><td><p style=\\\"text-align:center;\\\">1500 сум</p></td><td><p style=\\\"text-align:center;\\\">7*4*50</p></td><td><p style=\\\"text-align:center;\\\">SMS 50</p></td><td rowspan=\\\"4\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">0 сум за 1 запрос</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">2</p></td><td><p style=\\\"text-align:center;\\\">200 SMS</p></td><td><p style=\\\"text-align:center;\\\">5 000 сум</p></td><td><p style=\\\"text-align:center;\\\">7*4*200</p></td><td><p style=\\\"text-align:center;\\\">SMS 200</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">3</p></td><td><p style=\\\"text-align:center;\\\">500 SMS</p></td><td><p style=\\\"text-align:center;\\\">10 000 сум</p></td><td><p style=\\\"text-align:center;\\\">7*4*500</p></td><td><p style=\\\"text-align:center;\\\">SMS 500</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">4</p></td><td><p style=\\\"text-align:center;\\\">1 000 SMS</p></td><td><p style=\\\"text-align:center;\\\">20 000 сум</p></td><td><p style=\\\"text-align:center;\\\">7*4*1000</p></td><td><p style=\\\"text-align:center;\\\">SMS 1 000</p></td></tr><tr><td><p style=\\\"text-align:center;\\\">5</p></td><td><p style=\\\"text-align:center;\\\">Информация об остатке лимита&nbsp;SMS</p></td><td><p style=\\\"text-align:center;\\\">0 сум</p></td><td><p style=\\\"text-align:center;\\\">7*4*0</p></td><td><p style=\\\"text-align:center;\\\">SMS 0</p></td><td><p style=\\\"text-align:center;\\\">0 сум</p></td></tr></tbody></table></figure><p>&nbsp;</p><p>Лимит в SMS-пакете предоставляется только на исходящие SMS по Узбекистану (SMS-запросы на услуги контент-провайдеров тарифицируются отдельно, согласно установленным для них тарифам).</p><p>Стоимость сверх SMS-пакета 100 сум/SMS</p><p>Подключить SMS-пакеты можно не более 5 штук.</p><p>Не допускается одновременное использование более пяти SMS-пакетов. Абоненты, пользующиеся пятью SMS-пакетами, могут подключить 6-ой только после полного израсходования одного из пяти текущих SMS-пакетов.</p><p>Включенный в тарифный план SMS–трафик действует только после полного израсходования или при отсутствии SMS–пакетов.</p><p>Включенный в тарифный план SMS–трафиксуммируется с включенным SMS–пакетом. По окончании суммарного SMS-трафика (SMS в тарифном плане + «SMS–пакет») или по истечении срока пакета тарификация сверх лимита на всех тарифных планах устанавливается в зависимости от условий тарифного плана.</p><p>Приоритет использования «SMS-пакета»: «SMS–пакет» -&gt; «SMS–трафик в тарифном плане».</p><p>Срок действия пакета - 30 календарных дней. При активации каждого последующего пакета срок действия действующего пакета продлевается еще на 30 календарных дней, при этом предоставленные лимиты суммируются. Срок действия просуммированных SMS составляет 30 дней со дня подключения последнего пакета. По истечении 30 дней со дня активации SMS-пакета, при отсутствии активации нового, остаток SMS не сохраняется.</p><p>При снижении предоплаты до 1000 сум доступны только входящие SMS-сообщения.</p>\", \"uz\": \"<p><span style=\\\"color:rgb(255,102,0);\\\">*</span>Ushbu xizmatga&nbsp;<a href=\\\"http://www.perfectum.uz/service-show/programma-loyalnost\\\"><span style=\\\"color:rgb(230,0,0);\\\">“Ishonch”</span></a> dasturi bo\'yicha maxsus narxi amalda, abonent tajribasiga ko\'ra (misol: 10 yil =10%). Tajriba kanchalik ko\'p bo\'lsa, shunchalik xizmat arzon.&nbsp;</p><figure class=\\\"table\\\"><table style=\\\"border:1px dotted rgb(170, 170, 170);\\\"><tbody><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">№</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">SMS-paket</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">Narxi</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" colspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Aktivlashtirish</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">Tarifikatsiyasi USSD/SMS</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">&nbsp; &nbsp; &nbsp; &nbsp;USSD</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">0777ga SMS</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">1</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">50 SMS</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">1&nbsp;500 so\'m</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">7*4*50</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS 50</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\" rowspan=\\\"4\\\"><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">&nbsp;</p><p style=\\\"text-align:center;\\\">0 so\'m<br>1 so\'rov uchun</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">2</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">200 SMS</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">5 000 so\'m</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">7*4*200</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS 200</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">3</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">500 SMS</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">10 000 so\'m</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">7*4*500</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS 500</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">4</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">1 000 SMS</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">20 000 so\'m</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">7*4*1000</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS 1 000</p></td></tr><tr><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">5</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS qoldig\'i haqida ma\'lumot</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">0 so\'m</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">7*4*0</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">SMS 0</p></td><td style=\\\"border:1px dotted rgb(204, 204, 204);\\\"><p style=\\\"text-align:center;\\\">0 so\'m</p></td></tr></tbody></table></figure><p style=\\\"margin-left:0px;text-align:justify;\\\"><br>SMS-paketlardagi limiti O\'zbekiston bo\'yicha faqat chiquvchi SMS-lar uchun taqdim etiladi (kontent-provayderlar xizmati uchun SMS-so\'rovlar alohida hisoblanadi, o\'rnatilgan narxlar bo\'yicha).<br>SMS-paketdan yuqori narxi - 100 so\'m/SMS</p><p style=\\\"margin-left:0px;text-align:justify;\\\">5 dona SMS-paketni ulash mumkin.</p><p>Bir vaqtni o\'zida beshtadan ortiq SMS-paketlardan foydalanishga yo\'l qo\'yilmaydi. Beshta SMS -paketlar bilan foydalanayotgan abonentlar, faqat joriy beshtadan SMS -paketlaridan biri to\'liq sarflangandan so\'ng, 6-chi SMS-paketni ulashlari mumkin.<br>Tarif rejasiga kiritilgan SMS-trafik faqat to\'liq ishlatilganidan yoki SMS-paket yoqligida amal qiladi.<br>Tarif rejasiga kiritilgan SMS-trafik yoqilgan SMS-paket bilan qo\'shiladi. Jami SMS-trafik tugagandan so\'ng (tarif rejasidagi SMS + \\\"SMS-paket\\\") yoki paket muddati tugagandan so\'ng, barcha tarif rejalarida limitdan oshib ketadigan tarif reja shartlariga qarab belgilanadi.<br>\\\"SMS-paket\\\" dan foydalanish ustuvorligi: \\\"SMS–paketi\\\" -&gt; \\\"tarif rejasidagi SMS–trafik\\\".</p><p>Paketni amal qilish muddati - 30 kalendar kuni. Har bir keyingi paket faollashtirilganda, amaldagi paket muddati yana 30 kalendar kuniga uzaytiriladi va taqdim etilgan limitlar qo\'shilib boriladi. Birlashtirilgan SMS-ning amal qilish muddati oxirgi paket faollashtirilgan kundan boshlab 30 kun. SMS paket yoqilgan kunidan boshlab 30 kundan keyin, agar yangisi yoqilmagan bo\'lsa, SMS-ning qoldig\'i saqlanmaydi.</p><p>Oldindan to\'lov 1000 so\'mga tushganda faqat kirish SMS xabarlari mavjud bo\'ladi.</p>\"}', '{\"ru\": null}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": \"sms-pakety\", \"uz\": \"sms-paketlar\"}', 'images/aSZ9dFtgaFzoH6aZ9qBE9bnZ99ZWthSGyN8SSc5x.svg', 'images/LyOEe2HErfxcqckKWtjjewQLSIPKUNTcqQ4d0KHz.svg', 1, '2022-05-22 19:00:00', NULL, 0),
(61, 2, NULL, '{\"ru\": \"Детализация услуг связи\", \"uz\": \"Aloqa xizmatini detalizatsiyasi.\"}', '{\"ru\": \"Детализация услуг связи\", \"uz\": \"Aloqa xizmatini detalizatsiyasi.\"}', '{\"ru\": null}', '{\"ru\": \"<p style=\\\"margin-left:0px;\\\">&nbsp;</p><p style=\\\"margin-left:0px;text-align:justify;\\\">Теперь Вы можете самостоятельно получить услугу <span style=\\\"color:rgb(230,0,0);\\\">«Детализация услуг связи»</span>, воспользовавшись <a href=\\\"http://my.cdma.uz/login.php\\\"><span style=\\\"color:rgb(230,0,0);\\\">Персональным кабинетом</span></a>&nbsp;в любое удобное для Вас время и не приходя в офис компании!<br>Будьте внимательны! Вы несете полную ответственность за все действия и изменения, производимые с вашего телефона!<br>Если у Вас не была ранее активирована услуга «Персональный кабинет», то необходимо его подключить<i>.</i></p><p style=\\\"margin-left:0px;text-align:justify;\\\">КАК ПОДКЛЮЧИТЬ/ОТКЛЮЧИТЬ услугу «Персональный кабинет»?<br>-&nbsp;Для физических лиц, индивидуальных предпринимателей:</p><figure class=\\\"table\\\"><table><tbody><tr><td><p style=\\\"margin-left:0px;text-align:center;\\\">Способ</p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">Подключить</p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">Отключить</p></td></tr><tr><td><p style=\\\"margin-left:0px;text-align:center;\\\">USSD команда</p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">9*19<img src=\\\"http://www.perfectum.uz/storage/images/RswX2zJCCHs0PO5bf8jY3TpVZ72ad65tJmabNILU.gif\\\"></p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">9*19*0<img src=\\\"http://www.perfectum.uz/storage/images/RswX2zJCCHs0PO5bf8jY3TpVZ72ad65tJmabNILU.gif\\\"></p></td></tr><tr><td><p style=\\\"margin-left:0px;text-align:center;\\\">SMS-код на номер&nbsp;0998</p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">19</p></td><td><p style=\\\"margin-left:0px;text-align:center;\\\">STOP 19</p></td></tr></tbody></table></figure><p style=\\\"margin-left:0px;text-align:justify;\\\">Стоимость 1 запроса – 0 сум.<br>-&nbsp;Юридическому лицу: необходимо письмо с печатью и указанием об ответственности за все внесенные изменения через Персональный кабинет. Персональный кабинет можно подключить/отключить только тому лицу, с которым заключен договор и по предъявлению соответствующего документа, удостоверяющего его личность.</p><p style=\\\"margin-left:0px;text-align:justify;\\\">Условия предоставления услуги « Персональный кабинет»:<br><span style=\\\"background-color:rgb(255,255,255);color:rgb(116,116,116);\\\">-&nbsp;Услуга доступна на любом тарифном плане всем абонентам сети Perfectum: физическим лицам, достигшим 18 лет: гражданам Республики Узбекистан, постоянно проживающим на территории Республики Узбекистан, иностранным гражданам и лицам без гражданства, имеющим вид на жительство, индивидуальным предпринимателям, юридическим лицам, в том числе «Корпоративным».</span><br><span style=\\\"background-color:rgb(255,255,255);color:rgb(116,116,116);\\\">-&nbsp;Услугу можно подключить только на 1 (один) ресурс Договора на предоставление услуг подвижной радиотелефонной (сотовой) связи, независимо от количества номеров и типа абонента.</span><br><br>Условия предоставления услуги «Детализация услуг связи»:<br>-&nbsp;Услуга предоставляется для самостоятельного получения абонентом детализации данных услуг связи по любому абонентскому номеру, подключенному на контракте абонента в Персональном кабинете.<br>- Детализация услуг связи предоставляется только за последние 3 (три) месяца, а также в течение месяца запроса на детализацию.<br>-&nbsp;Стоимость в размере 25 000 сум взимается до предоставления услуги за 1 (один) полный календарный месяц, независимо от количества дней заказанной детализации. Если на балансе ресурса недостаточно денежных средств, услуга не предоставляется.<br>-&nbsp;Услуга доступна на любом тарифном плане всем абонентам сети Perfectum -&nbsp;физическим лицам, достигшим 18 лет: гражданам Республики Узбекистан, постоянно проживающим на территории Республики Узбекистан, иностранным гражданам и лицам без гражданства, имеющим вид на жительство, индивидуальным предпринимателям, юридическим лицам, в том числе «Корпоративным».</p>\", \"uz\": \"<p style=\\\"margin-left:0px;text-align:justify;\\\">Endi Siz mustaqil ravishda “Аloqa xizmatlarining detalizatsiyasi” xizmatini <a href=\\\"http://www.perfectum.uz/\\\">www.perfectum.uz</a> saytidagi <span style=\\\"color:rgb(230,0,0);\\\">Shaxsiy kabinetingizdan</span> foydalanib, o\'zingiz uchun qulay vaqtda va kompaniya ofisiga kelmasdan olishingiz mumkin!</p><p>Diqqat! Siz telefoningiz orqali amalga oshirilgan barcha harakatlar va o\'zgarishlar uchun to\'liq javobgarsiz!<br>Аgar sizda Shaxsiy kabinet xizmati faollashtirilmagan bo\'lsa, uni ulashingiz kerak.</p><p style=\\\"margin-left:0px;text-align:justify;\\\">“Shaxsiy kabinet” xizmatini QАNDАY ULАSH/O\'CHIRISH?<br>&nbsp;Jismoniy shaxslar uchun, yakka tartibdagi tadbirkorlarga:</p><figure class=\\\"table\\\" style=\\\"width:832px;\\\"><table style=\\\"border:1px dotted rgb(153, 153, 153);\\\"><tbody><tr><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">Usul</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">Ulanish</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">O\'chirish</p></td></tr><tr><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">USSD so\'rov</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">9*19📞</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">9*19*0📞</p></td></tr><tr><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">0998 raqamiga SMS-kodi</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">19</p></td><td style=\\\"border:1px dotted rgb(153, 153, 153);padding:0.75rem;vertical-align:top;\\\"><p style=\\\"margin-left:0px;text-align:center;\\\">STOP 19</p></td></tr></tbody></table></figure><p style=\\\"margin-left:0px;text-align:justify;\\\">1 so\'rov narxi – 0 so\'m.<br>- Yuridik shaxsga: Shaxsiy kabinetdagi barcha o\'zgarishlar uchun javobgarlik belgisi va muhr bosilgan xat kerak.Shaxsiy kabinet faqat shartnoma tuzilgan shaxsga va uning shaxsini tasdiqlovchi tegishli xujjat taqdim etilgandan keyingina ulanishi yoki o\'chirilishi mumkin. «Shaxsiy kabinet» xizmatining taqdim qilinish shartlari:<br>- Xizmat Perfectumning barcha abonentlari uchun har qanday tarif rejalarida mavjud: jismoniy shaxslar 18 yoshga to\'lganlar: O\'zbekiston Respublikasi fuqarolari, har doim O\'zbekistonda yashab kelayotganlar, chet el fuqarolari va yashash guvoxnomasiga ega bo\'lgan fuqaroligi bo\'lmamgan shaxslar, hamda yuridik shaxslar, “Korporativ” abonentlari ham.<br>- Xizmatga abonent turidan va raqamlar sonidan ka\'tiy nazar radiotelefon (uyali) aloqa xizmatlarini taqdim etish Shartnomasining faqat (bitta) resursiga ulanish mumkin.<br><br>«Аloqa xizmatlari detalizatsiyasi» xizmatning taqdim qilinish shartlari:<br>- Ushbu xizmat abonentga Shaxsiy kabinetda abonent Sharnomasiga ulangan istalgan abonent raqami orqali ushbu aloqa xizmatlari haqidagi detalizatsiyasini mustaqil ravishda olish uchun taqdim etiladi.<br>- Аloqa xizmatlari detalizatsiyasi faqat oxirgi 3 (uch) oy davomida, shunindek batafsil ma\'lumot olish uchun so\'ralgan oy davomida taqdim etiladi.<br>- Xizmatni taqdim etishdan oldin 1 (bir) to\'liq kalendar oyi uchun 25 000 so\'m olinadi, detalizatsiya buyurtma qilingan kunlar sonidan ka\'tiy nazar. Аgar balansa pul mablag\'i yetarli bo\'lmasa, xizmat taqdim etilmaydi.<br>- Xizmat Perfectumning barcha abonentlari uchun istalgan tarif rejalarida mavjud: jismoniy shaxslar 18 yoshga to\'lganlar: O\'zbekiston Respublikasi fuqarolari, har doim O\'zbekistonda yashab kelayotganlar, chet el fuqarolari va yashash guvoxnomasiga ega bo\'lgan fuqaroligi bo\'lmamgan shaxslar, hamda yuridik shaxslar, “Korporativ” abonentlari ham.</p>\"}', '{\"ru\": null}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"ru\": \"-\", \"uz\": \"-\"}', '{\"uz\": null}', '{\"ru\": null}', '{\"ru\": \"detalizaciya-uslug-svyazi\", \"uz\": \"aloqa-xizmatini-detalizatsiyasi\"}', 'images/VMD6fTNWYukyWEIWXFl52vCmKgd3Liu7zVSusbIT.svg', 'images/tdCKJLqPmQQfH4vSbh26t7hu5GBK9LRY2kM9pmGW.svg', 1, '2022-06-26 19:00:00', NULL, 0);
INSERT INTO `services` (`id`, `service_type_id`, `type_view`, `name`, `title`, `teaser`, `description`, `description_comment`, `subscription_price`, `service_billing`, `billing_description`, `billing_description_comment`, `slug`, `image`, `icon`, `show_all_time`, `created_date`, `merchant_id`, `is_merchant`) VALUES
(62, 9, NULL, '{\"ru\": \"ТЕМАТИЧЕСКИЕ УСЛУГИ (UZ/RU)\", \"uz\": \"TEMATIK XIZMATLAR (UZ/RU)\"}', '{\"ru\": \"ㅤ\", \"uz\": \"-\"}', NULL, '{\"ru\": \"<figure class=\\\"table\\\"><table style=\\\"border:1.0pt dotted #AAAAAA;\\\"><tbody><tr><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:95.3pt;\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Тематика</p></td><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:238.6pt;\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Язык (UZ - на узб. яз., RU - на рус.яз.), название, краткое описание сервиса, номер, стоимость</p></td><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:276.25pt;\\\" colspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">SMS-код подписки/отписки, сервисный номер</p></td><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:142.85pt;\\\" rowspan=\\\"2\\\"><p style=\\\"text-align:center;\\\">Контент-провайдер</p></td></tr><tr><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:157.25pt;\\\"><p style=\\\"text-align:center;\\\">подписка</p></td><td style=\\\"border:1.0pt dotted #CCCCCC;height:12.75pt;padding:0cm;width:119.0pt;\\\"><p style=\\\"text-align:center;\\\">отписка</p></td></tr><tr><td style=\\\"border:1.0pt dotted #CCCCCC;padding:0cm;\\\">Время Намаза</td><td style=\\\"border:1.0pt dotted #CCCCCC;padding:0cm;\\\">UZ.&nbsp;«Namoz Vaqti».&nbsp;Услуга позволяет получать точное и актуальное время намаза на следующий день.<br>Чтобы подписаться на услугу, необходимо отправить SMS-код, в зависимости от региона,<br>на бесплатный сервисный номер&nbsp;123.<br>Чтобы отписаться от услуги - отправить SMS с кодом,<br>в зависимости от региона, на сервисный номер&nbsp;123.<br>Стоимость: №123 - 0 сум, №213 - 796 сум/входящее SMS</td><td style=\\\"border:1.0pt dotted #CCCCCC;padding:0cm;\\\">SMS-коды подписки/отписки по регионам:<br>Андижанский -&nbsp;<br>NA7&nbsp;на №123<br>Бухарс