(79, 4, NULL, '{\"ru\": \"Персональный кабинет ㅤㅤㅤ для CDMA\", \"uz\": \"CDMA Shaxsiy kabinet\"}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": \"<p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Вход в </span><a href=\\\"http://my.perfectum.uz/\\\"><span style=\\\"color:rgb(230,0,0);font-family:Arial, Helvetica, sans-serif;\\\">Персональный кабинет</span></a><span style=\\\"color:rgb(230,0,0);font-family:Arial, Helvetica, sans-serif;\\\"> </span><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">для CDMA</span></p>\", \"uz\": \"<p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">CDMA </span><a href=\\\"http://my.perfectum.uz/\\\"><span style=\\\"color:rgb(230,0,0);font-family:Arial, Helvetica, sans-serif;\\\">Shaxsiy kabinetga</span></a><span style=\\\"color:rgb(230,0,0);font-family:Arial, Helvetica, sans-serif;\\\"> </span><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">kirish</span></p>\"}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": \"personalnyi-kabinet-dlya-cdma\", \"uz\": \"cdma-shaxsiy-kabinet\"}', 'images/BMOYJ5nT8ifgXdBBTmizXoq1BOObEPQZ4MgvKabS.svg', 'images/sZ1uNiFI0m5PGwYOE3nsqFFaSibSl4WNRyOGoNE7.svg', 1, '2024-11-30 19:00:00', 1648, 0);
INSERT INTO `services` (`id`, `service_type_id`, `type_view`, `name`, `title`, `teaser`, `description`, `description_comment`, `subscription_price`, `service_billing`, `billing_description`, `billing_description_comment`, `slug`, `image`, `icon`, `show_all_time`, `created_date`, `merchant_id`, `is_merchant`) VALUES
(81, 13, 4, '{\"ru\": \"Услуга «Статический IP-адрес»\", \"uz\": \"Xizmat “Statik IP-manzil”\"}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": \"<p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Статический IP — это постоянный уникальный адрес вашего устройства в Интернете.</span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Он не меняется ни после перезагрузки оборудования, ни при новом подключении — адрес закреплён за вашим абонентским номером на весь срок действия услуги.</span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Подходит для:</span></p><ul><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">удалённого доступа к видеонаблюдению и оборудованию</span></li><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">VPN-подключений и корпоративных сервисов</span></li><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">размещения собственных серверов и приложений</span></li></ul><p><br><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\"><strong>Стоимость: 50 000 сум / 30 дней</strong></span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Подключение доступно через Абонентский отдел или Контакт-центр</span></p>\", \"uz\": \"<p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Statik IP — bu Internetda qurilmangizga biriktirilgan doimiy va noyob manzil.</span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">U uskunani qayta ishga tushirganda yoki tarmoqga qayta ulanayotganda ham o‘zgarmaydi: manzil xizmat faol bo‘lgan muddat davomida sizning abonent raqamingizga biriktiriladi.</span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Quyidagilar uchun mos:</span></p><ul><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">videokuzatuv tizimlari va uskunalarga masofaviy kirish</span></li><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">VPN ulanishlari va korporativ servislar</span></li><li><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">shaxsiy serverlar va ilovalarni joylashtirish</span></li></ul><p><br><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\"><strong>Narxi: 50 000 so‘m / 30 kun</strong></span></p><p><span style=\\\"font-family:Arial, Helvetica, sans-serif;\\\">Ulanish: Abonentlar bo‘limi yoki Kontakt-markaz orqali.</span></p>\"}', '{\"ru\": null}', '{\"ru\": null}', '{\"ru\": null}', '{\"uz\": null}', '{\"ru\": null}', '{\"ru\": \"usluga-staticeskii-ip-adres\", \"uz\": \"xizmat-statik-ip-manzil\"}', 'images/TsE89YCBv9Ur5AcBIj5rU0uc6O3XH6Z9XCjG6dMx.svg', 'images/pDjoBoH3ommdLrs4Cfm7tfPW9vzpbkJiAm9GxUrc.svg', 1, '2026-03-31 19:00:00', NULL, 0);

